VALUES
  ('optometrist-moex-00004', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列有關視障流行病學的敘述，何者錯誤？', '["視障的成因，會因著國家的發展狀態有所不同", "高度開發的國家中，致盲的成因以黃斑部病變為主", "世界視障人口之中，屈光不正及白內障這類簡單醫治的疾病所占比例較少，無法醫治的眼疾如神經病變 等所占比例較高", "假設一國家人口有5億，其中有720萬人口為視障，則其視障的患病率（prevalence）為1.4%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00005', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '在已開發國家中，下列何種疾病不是導致目盲（blindness）的常見原因？', '["老年性黃斑部病變", "糖尿病相關的視網膜病變", "維生素A缺乏", "青光眼"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00006', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '常見的致盲眼疾對於視力視野的影響，下列敘述何者正確？', '["老年性黃斑部病變通常先影響患眼周邊的視力", "青光眼首先影響患眼的中央視力", "糖尿病視網膜病變可影響中央或是周邊視力", "任何視力下降都不會影響深度知覺的能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00007', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列有關各種近距離放大鏡的敘述，何者錯誤？', '["相同度數正屈光度的眼鏡與手持式放大鏡比較，有更寬廣的視野", "使用手持式放大鏡來觀看物體，當鏡片越遠離眼睛時，視野會越縮小", "近距離觀看的望遠鏡相對於正屈光度的眼鏡或是手持式放大鏡，主要的優點在於比較長的工作距離", "伽利略式（Galilean）的望遠鏡是使用負屈光度的接目鏡，相較於相同倍數的開普勒式（Keplerian）望遠 鏡，視野比較大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00008', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有一位低視力患者，殘餘遠視力為0.08，若欲求此患者能看清0.5視標的遠用望遠鏡助視器的放大倍率為何？', '["7.1", "6.25", "5", "3.2"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00009', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視能者使用手持式放大鏡作為放大輔具的優缺點，下列敘述何者錯誤？', '["比起眼鏡可有較短的工作距離", "能夠有內建的照明", "比起眼鏡的視野狹窄", "需要使用一隻手穩定的控制來拿握放大鏡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
